const crypto = require('crypto');
const secret = $env.N8N_HOOK_SECRET || '';
const raw = $input.first().binary?.data?.data ? Buffer.from($input.first().binary.data.data, 'base64').toString('utf8') : JSON.stringify($input.first().json);
const header = $input.first().headers?.['x-signature'] || '';
const cleaned = String(header).replace(/^sha256=/, '').trim();
const expected = crypto.createHmac('sha256', secret).update(raw).digest('hex');
const valid = secret && cleaned && cleaned.length === expected.length && crypto.timingSafeEqual(Buffer.from(cleaned,'hex'), Buffer.from(expected,'hex'));
if (!valid) { throw new Error('Invalid signature - rejecting webhook'); }
return [{ json: JSON.parse(raw) }];
